  1→import { requireConfig, getDirCacheEntry, setDirCacheEntry, type DirCacheEntry } from "../config";
  2→import { BrainHttpClient } from "../http-client";
  3→
  4→/**
  5→ * brain system load-context
  6→ * Called by SessionStart hook. Outputs context as additionalContext text.
  7→ */
  8→export async function runLoadContext(): Promise<void> {
  9→  const config = await requireConfig();
 10→  const client = new BrainHttpClient(config);
 11→  const cwd = process.cwd();
 12→
 13→  // Check dir cache for cached project
 14→  const cached = await getDirCacheEntry(cwd);
 15→
 16→  if (cached) {
 17→    // Load context for cached project
 18→    try {
 19→      // Create session first so we can exclude self from active sessions
 20→      let sessionId: string | undefined;
 21→      try {
 22→        const session = await client.sessionStart({
 23→          agent: "claude-code",
 24→          project_id: cached.project_id,
 25→        });
 26→        sessionId = session.session_id;
 27→      } catch {
 28→        // Session creation failure must not break context loading
 29→      }
 30→
 31→      const context = await client.getContext({
 32→        project_id: cached.project_id,
 33→        since: cached.last_session,
 34→        session_id: sessionId,
 35→      });
 36→
 37→      // Output as text for Claude Code additionalContext
 38→      console.log(formatContextPacket(context));
 39→
 40→      await setDirCacheEntry(cwd, {
 41→        ...cached,
 42→        session_id: sessionId,
 43→        last_session: new Date().toISOString(),
 44→      });
 45→    } catch (error) {
 46→      console.error(`Failed to load context: ${error instanceof Error ? error.message : error}`);
 47→    }
 48→    return;
 49→  }
 50→
 51→  // No cached project — list projects for agent inference
 52→  try {
 53→    const projectsResult = await client.getProjects();
 54→    const projects = projectsResult.projects;
 55→
 56→    if (projects.length === 0) {
 57→      console.log("No projects found in workspace. Create one in the Brain web UI first.");
 58→      return;
 59→    }
 60→
 61→    if (projects.length === 1) {
 62→      // Single project — auto-select
 63→      const project = projects[0];
 64→      const entry: DirCacheEntry = {
 65→        project_id: project.id,
 66→        project_name: project.name,
 67→        last_session: new Date().toISOString(),
 68→      };
 69→
 70→      // Create session first so we can exclude self from active sessions
 71→      try {
 72→        const session = await client.sessionStart({
 73→          agent: "claude-code",
 74→          project_id: project.id,
 75→        });
 76→        entry.session_id = session.session_id;
 77→      } catch {
 78→        // Session creation failure must not break context loading
 79→      }
 80→
 81→      const context = await client.getContext({
 82→        project_id: project.id,
 83→        session_id: entry.session_id,
 84→      });
 85→      console.log(formatContextPacket(context));
 86→
 87→      setDirCacheEntry(cwd, entry);
 88→      return;
 89→    }
 90→
 91→    // Multiple projects — output list for agent to select
 92→    console.log(`You're working in: ${cwd}`);
 93→    console.log(`Workspace: ${projectsResult.workspace.name}`);
 94→    console.log(`\nProjects in this workspace:`);
 95→    for (const p of projects) {
 96→      console.log(`  - ${p.name} (id: ${p.id})`);
 97→    }
 98→    console.log(`\nTo set your project for this directory, run:`);
 99→    console.log(`  brain system set-project <project-id>`);
100→  } catch (error) {
101→    console.error(`Failed to load projects: ${error instanceof Error ? error.message : error}`);
102→  }
103→}
104→
105→/**
106→ * brain system set-project <project-id>
107→ * Cache a project for the current directory.
108→ */
109→export async function runSetProject(projectId: string): Promise<void> {
110→  const config = await requireConfig();
111→  const client = new BrainHttpClient(config);
112→  const cwd = process.cwd();
113→
114→  const projectsResult = await client.getProjects();
115→  const project = projectsResult.projects.find((p) => p.id === projectId);
116→
117→  if (!project) {
118→    console.error(`Project not found: ${projectId}`);
119→    console.error("Available projects:");
120→    for (const p of projectsResult.projects) {
121→      console.error(`  - ${p.name} (id: ${p.id})`);
122→    }
123→    process.exit(1);
124→  }
125→
126→  await setDirCacheEntry(cwd, {
127→    project_id: project.id,
128→    project_name: project.name,
129→    last_session: new Date().toISOString(),
130→  });
131→
132→  console.log(`Project set: ${project.name} (${project.id}) for ${cwd}`);
133→}
134→
135→/**
136→ * brain system check-updates
137→ * Called by UserPromptSubmit hook. Outputs alerts for critical changes.
138→ */
139→export async function runCheckUpdates(): Promise<void> {
140→  const config = await requireConfig();
141→  const client = new BrainHttpClient(config);
142→  const cwd = process.cwd();
143→
144→  const cached = await getDirCacheEntry(cwd);
145→  if (!cached?.last_session) return;
146→
147→  try {
148→    const result = (await client.getChanges({
149→      project_id: cached.project_id,
150→      since: cached.last_session,
151→    })) as { changes: Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> };
152→
153→    if (!result.changes || result.changes.length === 0) return;
154→
155→    // Check for critical changes
156→    const critical = result.changes.filter(
157→      (c) => c.change_type === "contested" || c.change_type === "superseded",
158→    );
159→
160→    if (critical.length > 0) {
161→      console.log("\n--- Context Update ---");
162→      for (const c of critical) {
163→        console.log(`[${c.entity_type}] ${c.entity_name} — ${c.change_type} at ${c.changed_at}`);
164→      }
165→      console.log("--- End Update ---\n");
166→    }
167→
168→    // Cross-agent activity: provisional decisions and observations from other agents
169→    const crossAgent = result.changes.filter(
170→      (c) =>
171→        c.change_type === "provisional" ||
172→        (c.entity_type === "observation" && (c.change_type === "warning" || c.change_type === "conflict")),
173→    );
174→
175→    if (crossAgent.length > 0) {
176→      console.log("\n--- Cross-Agent Activity ---");
177→      for (const c of crossAgent) {
178→        console.log(`[${c.entity_type}] ${c.entity_name} — ${c.change_type}`);
179→      }
180→      console.log("--- End ---\n");
181→    }
182→
183→    // New suggestions
184→    const newSuggestions = result.changes.filter(
185→      (c) => c.entity_type === "suggestion" && c.change_type === "pending",
186→    );
187→    if (newSuggestions.length > 0) {
188→      console.log("\n--- New Suggestions ---");
189→      for (const s of newSuggestions) {
190→        console.log(`[suggestion] ${s.entity_name}`);
191→      }
192→      console.log("--- End ---\n");
193→    }
194→
195→    // Update last check time
196→    await setDirCacheEntry(cwd, { ...cached, last_session: new Date().toISOString() });
197→  } catch {
198→    // Silent on error — don't block the user
199→  }
200→}
201→
202→/**
203→ * brain system end-session
204→ * Called by SessionEnd hook.
205→ */
206→export async function runEndSession(): Promise<void> {
207→  const config = await requireConfig();
208→  const client = new BrainHttpClient(config);
209→  const cwd = process.cwd();
210→  const cached = await getDirCacheEntry(cwd);
211→
212→  if (!cached) return; // No project mapped — nothing to end
213→
214→  try {
215→    // Read stdin (Claude Code pipes Stop hook JSON)
216→    let stdinText = "";
217→    try {
218→      const chunks: Buffer[] = [];
219→      for await (const chunk of Bun.stdin.stream()) {
220→        chunks.push(Buffer.from(chunk));
221→      }
222→      stdinText = Buffer.concat(chunks).toString("utf-8").trim();
223→    } catch {
224→      // stdin not available or empty
