360→// Format helpers
361→// ---------------------------------------------------------------------------
362→
363→function formatContextPacket(packet: unknown): string {
364→  const p = packet as Record<string, unknown>;
365→  const lines: string[] = [];
366→
367→  lines.push("# Brain Knowledge Graph Context\n");
368→
369→  // Workspace & project
370→  const ws = p.workspace as { id: string; name: string } | undefined;
371→  const proj = p.project as { id: string; name: string; status: string; description?: string } | undefined;
372→  if (ws) lines.push(`Workspace: ${ws.name}`);
373→  if (proj) {
374→    lines.push(`Project: ${proj.name} (${proj.status})`);
375→    if (proj.description) lines.push(`Description: ${proj.description}`);
376→  }
377→  lines.push("");
378→
379→  // Task scope
380→  const taskScope = p.task_scope as Record<string, unknown> | undefined;
381→  if (taskScope) {
382→    const task = taskScope.task as { id: string; title: string; status: string; description?: string };
383→    lines.push(`## Current Task: ${task.title} [${task.status}]`);
384→    if (task.description) lines.push(task.description);
385→
386→    const subtasks = taskScope.subtasks as Array<{ id: string; title: string; status: string }>;
387→    if (subtasks?.length) {
388→      lines.push("\nSubtasks:");
389→      for (const s of subtasks) lines.push(`  - [${s.status}] ${s.title}`);
390→    }
391→
392→    const siblings = taskScope.sibling_tasks as Array<{ id: string; title: string; status: string }>;
393→    if (siblings?.length) {
394→      lines.push("\nSibling tasks:");
395→      for (const s of siblings) lines.push(`  - [${s.status}] ${s.title}`);
396→    }
397→    lines.push("");
398→  }
399→
400→  // Decisions
401→  const decisions = p.decisions as { confirmed: unknown[]; provisional: unknown[]; contested: unknown[] } | undefined;
402→  if (decisions) {
403→    if (decisions.contested.length > 0) {
404→      lines.push("## CONTESTED DECISIONS (conflicts — do not proceed without human input)");
405→      for (const d of decisions.contested as Array<{ summary: string; rationale?: string }>) {
406→        lines.push(`  - ${d.summary}${d.rationale ? ` — ${d.rationale}` : ""}`);
407→      }
408→      lines.push("");
409→    }
410→
411→    if (decisions.confirmed.length > 0) {
412→      lines.push("## Confirmed Decisions (follow these)");
413→      for (const d of decisions.confirmed as Array<{ summary: string }>) {
414→        lines.push(`  - ${d.summary}`);
415→      }
416→      lines.push("");
417→    }
418→
419→    if (decisions.provisional.length > 0) {
420→      lines.push("## Provisional Decisions (follow but flag for review)");
421→      for (const d of decisions.provisional as Array<{ summary: string }>) {
422→        lines.push(`  - ${d.summary}`);
423→      }
424→      lines.push("");
425→    }
426→  }
427→
428→  // Active tasks
429→  const tasks = p.active_tasks as Array<{ title: string; status: string; priority?: string }> | undefined;
430→  if (tasks?.length) {
431→    lines.push("## Active Tasks");
432→    for (const t of tasks) {
433→      lines.push(`  - [${t.status}]${t.priority ? ` (${t.priority})` : ""} ${t.title}`);
434→    }
435→    lines.push("");
436→  }
437→
438→  // Open questions
439→  const questions = p.open_questions as Array<{ text: string; status: string }> | undefined;
440→  if (questions?.length) {
441→    lines.push("## Open Questions");
442→    for (const q of questions) {
443→      lines.push(`  - [${q.status}] ${q.text}`);
444→    }
445→    lines.push("");
446→  }
447→
448→  // Recent changes
449→  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
450→  if (changes?.length) {
451→    lines.push("## Recent Changes");
452→    for (const c of changes) {
453→      lines.push(`  - [${c.entity_type}] ${c.entity_name} — ${c.change_type}`);
454→    }
455→    lines.push("");
456→  }
457→
458→  // Observations
459→  const observations = p.observations as Array<{ text: string; severity: string }> | undefined;
460→  if (observations?.length) {
461→    lines.push("## Observations");
462→    for (const o of observations) {
463→      lines.push(`  - [${o.severity}] ${o.text}`);
464→    }
465→    lines.push("");
466→  }
467→
468→  // Pending suggestions
469→  const suggestions = p.pending_suggestions as Array<{ text: string; category: string; confidence: number; rationale: string }> | undefined;
470→  if (suggestions?.length) {
471→    lines.push("## Pending Suggestions");
472→    for (const s of suggestions) {
473→      lines.push(`  - [${s.category}] (${s.confidence.toFixed(2)}) ${s.text} — ${s.rationale}`);
474→    }
475→    lines.push("");
476→  }
477→
478→  // Active agent sessions (cross-agent awareness)
479→  type ActiveSession = {
480→    agent: string;
481→    started_at: string;
482→    task?: { id: string; title: string };
483→    provisional_decisions: Array<{ summary: string }>;
484→    observations: Array<{ text: string; severity: string }>;
485→  };
486→  const activeSessions = p.active_sessions as ActiveSession[] | undefined;
487→  if (activeSessions?.length) {
488→    lines.push("## Active Agent Sessions");
489→    for (const s of activeSessions) {
490→      const ago = formatTimeAgo(s.started_at);
491→      lines.push(`  - ${s.agent} (started ${ago})`);
492→      if (s.task) {
493→        lines.push(`    Working on: ${s.task.title}`);
494→      }
495→      if (s.provisional_decisions.length > 0) {
496→        lines.push("    Provisional decisions:");
497→        for (const d of s.provisional_decisions) {
498→          lines.push(`      - ${d.summary}`);
499→        }
500→      }
501→      if (s.observations.length > 0) {
502→        lines.push("    Observations:");
503→        for (const o of s.observations) {
504→          lines.push(`      - [${o.severity}] ${o.text}`);
505→        }
506→      }
507→    }
508→    lines.push("");
509→  }
510→
511→  return lines.join("\n");
512→}
513→
514→function formatTimeAgo(isoString: string): string {
515→  const diff = Date.now() - new Date(isoString).getTime();
516→  const minutes = Math.floor(diff / 60000);
517→  if (minutes < 1) return "just now";
518→  if (minutes < 60) return `${minutes}m ago`;
519→  const hours = Math.floor(minutes / 60);
520→  if (hours < 24) return `${hours}h ago`;
521→  return `${Math.floor(hours / 24)}d ago`;
522→}
