 49→/**
 50→ * brain system check-updates
 51→ * Called by UserPromptSubmit hook. Outputs alerts for critical changes.
 52→ */
 53→export async function runCheckUpdates(): Promise<void> {
 54→  const config = await requireConfig();
 55→  const client = new BrainHttpClient(config);
 56→
 57→  const project = await resolveProject(() => client.getProjects());
 58→  if (!project) return; // Multi-project — skip silently
 59→
 60→  try {
 61→    const since = new Date(Date.now() - 5 * 60_000).toISOString(); // last 5 minutes
 62→    const result = (await client.getChanges({
 63→      project_id: project.id,
 64→      since,
 65→    })) as { changes: Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> };
 66→
 67→    if (!result.changes || result.changes.length === 0) return;
 68→
 69→    // Check for critical changes
 70→    const critical = result.changes.filter(
 71→      (c) => c.change_type === "contested" || c.change_type === "superseded",
 72→    );
 73→
 74→    if (critical.length > 0) {
 75→      console.log("\n--- Context Update ---");
 76→      for (const c of critical) {
 77→        console.log(`[${c.entity_type}] ${c.entity_name} — ${c.change_type} at ${c.changed_at}`);
 78→      }
 79→      console.log("--- End Update ---\n");
 80→    }
 81→
 82→    // Cross-agent activity: provisional decisions and observations from other agents
 83→    const crossAgent = result.changes.filter(
 84→      (c) =>
 85→        c.change_type === "provisional" ||
 86→        (c.entity_type === "observation" && (c.change_type === "warning" || c.change_type === "conflict")),
 87→    );
 88→
 89→    if (crossAgent.length > 0) {
 90→      console.log("\n--- Cross-Agent Activity ---");
 91→      for (const c of crossAgent) {
 92→        console.log(`[${c.entity_type}] ${c.entity_name} — ${c.change_type}`);
 93→      }
 94→      console.log("--- End ---\n");
 95→    }
 96→
 97→    // New suggestions
 98→    const newSuggestions = result.changes.filter(
 99→      (c) => c.entity_type === "suggestion" && c.change_type === "pending",
100→    );
101→    if (newSuggestions.length > 0) {
102→      console.log("\n--- New Suggestions ---");
103→      for (const s of newSuggestions) {
104→        console.log(`[suggestion] ${s.entity_name}`);
105→      }
106→      console.log("--- End ---\n");
107→    }
108→  } catch {
109→    // Silent on error — don't block the user
110→  }
111→}
112→
